"use client"

import React, { JSX } from "react"
import {
  resolveContent, isSectionEnabled,
} from "./resolve-content"
import {
  SectionComponentProps, PageConfig,
} from "./types"
import {
  HeroSection, StatsSection, TrustSection, ProgramsSection,
  ServicesSection, WhyCountrySection, FeaturesSection, ProcessSection,
  TestimonialsSection, RequirementsSection, CtaBanner,
  FaqSection, FaqSearchSection, BlogSection, TeamSection,
  StorySection, PillarsSection, NewsletterSection, ContactDetailsSection,
  GallerySection, ComparisonSection, GlossarySection, PageHeroSection,
  HighlightSection, BookingEmbedSection, CaseStudySection,
  ServiceDetailSection, GenericSection, PrivacyAccordion,
  IntakeWizardSection, PressReleasesListSection,
  FeedbackSection, BookingFormSection,
} from "./index"

// ═══════════════════════════════════════════════════════════════════════════════
// SECTION REGISTRY
// Map section IDs to React components. Add new sections here.
// ═══════════════════════════════════════════════════════════════════════════════

export const DEFAULT_SECTIONS: Record<string, React.ComponentType<SectionComponentProps>> = {
  "hero": HeroSection,
  "hero-section": HeroSection,
  "stats": StatsSection,
  "stats-grid": StatsSection,
  "trust-signals": TrustSection,
  "programs": ProgramsSection,
  "services": ServicesSection,
  "why-destination": WhyCountrySection,
  "why-country": WhyCountrySection,
  "features": FeaturesSection,
  "process-timeline": ProcessSection,
  "process": ProcessSection,
  "testimonials": TestimonialsSection,
  "requirements": RequirementsSection,
  "cta-banner": CtaBanner,
  "cta": CtaBanner,
  "faq": FaqSection,
  "faq-search": FaqSearchSection,
  "blog": BlogSection,
  "team": TeamSection,
  "story": StorySection,
  "pillars": PillarsSection,
  "newsletter": NewsletterSection,
  "contact": ContactDetailsSection,
  "contact-details": ContactDetailsSection,
  "contact-form": ContactDetailsSection,
  "gallery": GallerySection,
  "comparison": ComparisonSection,
  "glossary": GlossarySection,
  "page-hero": PageHeroSection,
  "highlights": HighlightSection,
  "booking-embed": BookingEmbedSection,
  "case-study": CaseStudySection,
  "caseStudy": CaseStudySection,
  "service-detail": ServiceDetailSection,
  "privacy": PrivacyAccordion,
  "guides": GuidesSection,
  "press-releases": PressReleasesListSection,
  "intakeWizard": IntakeWizardSection,
  "intake-wizard": IntakeWizardSection,
  "booking-form": BookingFormSection,
  "feedback": FeedbackSection,
}

export interface SectionsRendererProps {
  pageConfig?: PageConfig
  content?: Record<string, any>
  images?: Record<string, any>
  locale?: string
  header?: React.ReactNode
  footer?: React.ReactNode
  sectionOverrides?: Record<string, React.ComponentType<SectionComponentProps>>
}

/**
 * Creates a SectionsRenderer component with optional header/footer overrides.
 * Pass `header` and `footer` to provide custom layout components per client.
 */
export function createSectionsRenderer(
  HeaderComponent?: React.ComponentType<{ navigation?: any; locale?: string }>,
  FooterComponent?: React.ComponentType<{ footer?: any }>
) {
  return function SectionsRenderer({
    pageConfig, content, images, locale,
    sectionOverrides,
  }: SectionsRendererProps) {
    const sections = pageConfig?.sections || []
    const mergedMap = sectionOverrides
      ? { ...DEFAULT_SECTIONS, ...sectionOverrides }
      : DEFAULT_SECTIONS

    return (
      <div className="font-inter text-text-primary">
        {content?.navigation && HeaderComponent && (
          <HeaderComponent navigation={content.navigation} locale={locale} />
        )}
        <main>
          {sections.map((section: any, idx: number) => {
            if (section.enabledWhen && !isSectionEnabled(section.enabledWhen, content)) return null
            const Comp = mergedMap[section.id]
            if (Comp) {
              const sectionData = resolveContent(content, section.content || section.id)
              return (
                <Comp
                  key={section.id || idx}
